dtsPropsFor.StatCard:
label: string;
value: string;
sub?: string;
/** Tailwind text-color class for the value, e.g. "text-emerald-600". */
accent?: string;
icon?: React.ReactNode;
/** When set, the card becomes a button (e.g. to drill into its transactions). */
onClick?: () => void;

dtsPropsFor.EmptyState:
icon?: React.ReactNode;
title: string;
message: string;
children?: React.ReactNode;

dtsPropsFor.SortHeader:
/** The column this header sorts. */
sortKey: string;
label: string;
/** The currently active sort column. */
current: string;
asc: boolean;
onToggle: (key: string) => void;
/** 'right' puts the arrow left of the label so a right-aligned column stays flush. */
align?: 'left' | 'right';
/** false renders static text at the same width, so the header never jumps when sortability changes. */
sortable?: boolean;

dtsPropsFor.CategoryDonut:
/** Spending grouped by category, sorted high to low. */
data: { category: string; total: number; count: number }[];
/** Total spending shown in the donut center. */
total: number;
onSelect?: (category: string) => void;

dtsPropsFor.MonthlyTrend:
/** Per-month spending/income/net, oldest month first. */
data: { monthKey: string; spending: number; income: number; net: number }[];
/** Called with the "YYYY-MM" key when the user clicks a month's bars. */
onSelectMonth?: (monthKey: string) => void;

dtsPropsFor.SpendingHabitsCard:
/** Repeat-habit groups (e.g. from analysis.recurringPayments). */
items: {
  merchant: string;
  groupKey: string;
  keys: string[];
  ids: string[];
  category: string;
  count: number;
  months: number;
  avgAmount: number;
  monthlyEstimate: number;
  [k: string]: unknown;
}[];
onOpenGroup: (ids: string[]) => void;
